// source: swagger
// endpoint: GET /camel-service/ee/sports_live/home_match
// summary: 首页赛事数据（无鉴权）
// generated by tp api pull

import { test, expect } from '@playwright/test';

const BASE_URL = process.env.CAMELTV_BASE_URL || 'http://localhost:8000';

test.describe('GET /camel-service/ee/sports_live/home_match', () => {
  test.describe.configure({ retries: 2 });

  test('API-TC-SPORTS-GET-001: 正向请求 — 合法参数', async ({ request }) => {
    const response = await request.get(
      `${BASE_URL}/camel-service/ee/sports_live/home_match`,
      { params: {
      "day": "20260615"
} }
    );
  // 状态码校验
  expect(response.status()).toBe(200);

  const body = await response.json();
  // 返回值校验
  expect(body).toHaveProperty('status');
  expect(body).toHaveProperty('data');

  // Schema 校验
  expect(body.status).toBeDefined();  // TODO: 按 swagger schema 补类型断言
  expect(body.data).toBeDefined();  // TODO: 按 swagger schema 补类型断言

  // DB/Redis 校验：调用 sidecar 验证数据落库
  // const dbCheck = await request.get('/api/_test/verify-Sports');
  // expect(dbCheck.status()).toBe(200);
  });

  test('API-TC-SPORTS-GET-002: 入参校验 — 缺少必填参数', async ({ request }) => {
    const response = await request.get(
      `${BASE_URL}/camel-service/ee/sports_live/home_match`
    );
    // API 对缺失 day 参数使用当天日期作为默认值，仍返回 HTTP 200
    expect(response.status()).toBe(200);
  });

  test('API-TC-SPORTS-GET-003: 入参校验 — 非法参数值', async ({ request }) => {
    const response = await request.get(
      `${BASE_URL}/camel-service/ee/sports_live/home_match`,
      { params: { injected: "' OR '1'='1" } }
    );
    // 期望：400/422（被网关拒绝）或 200（安全过滤后正常返回）
    expect([200, 400, 422]).toContain(response.status());
  });
});
